package com.webox.common.enums;

import com.fasterxml.jackson.annotation.JsonCreator;
import com.fasterxml.jackson.annotation.JsonValue;

/** Taste richness preference (PRD §4.1): Light / Medium / Heavy — AI-reference, no hard sort. */
public enum TasteLevel {
    LIGHT("Light"),
    MEDIUM("Medium"),
    HEAVY("Heavy");

    private final String label;

    TasteLevel(String label) {
        this.label = label;
    }

    @JsonValue
    public String getLabel() {
        return label;
    }

    @JsonCreator
    public static TasteLevel from(String value) {
        for (TasteLevel t : values()) {
            if (t.name().equalsIgnoreCase(value) || t.label.equalsIgnoreCase(value)) {
                return t;
            }
        }
        throw new IllegalArgumentException("Unknown taste level: " + value);
    }
}

package com.webox.preference;

import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.webox.common.enums.Category;
import jakarta.persistence.AttributeConverter;
import jakarta.persistence.Converter;

import java.util.List;

/** Stores preferred cuisine categories as a readable JSON array in a TEXT column. */
@Converter
public class CategoryListConverter implements AttributeConverter<List<Category>, String> {

    private static final ObjectMapper MAPPER = new ObjectMapper();
    private static final TypeReference<List<Category>> TYPE = new TypeReference<>() {
    };

    @Override
    public String convertToDatabaseColumn(List<Category> attribute) {
        try {
            return MAPPER.writeValueAsString(attribute == null ? List.of() : attribute);
        } catch (Exception e) {
            throw new IllegalStateException("Failed to serialize categories", e);
        }
    }

    @Override
    public List<Category> convertToEntityAttribute(String dbData) {
        try {
            if (dbData == null || dbData.isBlank()) {
                return List.of();
            }
            return MAPPER.readValue(dbData, TYPE);
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse categories: " + dbData, e);
        }
    }
}

package com.webox.preference;

import com.webox.auth.User;
import com.webox.common.enums.Allergen;
import com.webox.common.enums.Category;
import com.webox.common.enums.SpiceLevel;
import com.webox.common.enums.TasteLevel;
import com.webox.menu.AllergenListConverter;
import jakarta.persistence.Column;
import jakarta.persistence.Convert;
import jakarta.persistence.Entity;
import jakarta.persistence.EnumType;
import jakarta.persistence.Enumerated;
import jakarta.persistence.FetchType;
import jakarta.persistence.Id;
import jakarta.persistence.JoinColumn;
import jakarta.persistence.MapsId;
import jakarta.persistence.OneToOne;
import jakarta.persistence.Table;

import java.math.BigDecimal;
import java.util.List;

/** Employee dietary preferences (PRD §4.1). All fields optional; empty = no preference. */
@Entity
@Table(name = "user_preferences")
public class UserPreference {

    @Id
    @Column(name = "user_id")
    private Long userId;

    @OneToOne(fetch = FetchType.LAZY, optional = false)
    @MapsId
    @JoinColumn(name = "user_id", nullable = false)
    private User user;

    /** Flagged allergens — dishes containing them trigger an add-to-cart warning (never filtered). */
    @Convert(converter = AllergenListConverter.class)
    @Column(nullable = false, columnDefinition = "TEXT")
    private List<Allergen> allergens = List.of();

    /** Preferred cuisines — boost ordering when the "For You" switch is on. */
    @Convert(converter = CategoryListConverter.class)
    @Column(nullable = false, columnDefinition = "TEXT")
    private List<Category> cuisines = List.of();

    @Enumerated(EnumType.STRING)
    @Column(name = "spice_level", length = 16)
    private SpiceLevel spiceLevel;

    @Enumerated(EnumType.STRING)
    @Column(length = 16)
    private TasteLevel taste;

    @Column(name = "budget_min", precision = 10, scale = 2)
    private BigDecimal budgetMin;

    @Column(name = "budget_max", precision = 10, scale = 2)
    private BigDecimal budgetMax;

    public Long getUserId() {
        return userId;
    }

    public User getUser() {
        return user;
    }

    public void setUser(User user) {
        this.user = user;
    }

    public List<Allergen> getAllergens() {
        return allergens;
    }

    public void setAllergens(List<Allergen> allergens) {
        this.allergens = allergens;
    }

    public List<Category> getCuisines() {
        return cuisines;
    }

    public void setCuisines(List<Category> cuisines) {
        this.cuisines = cuisines;
    }

    public SpiceLevel getSpiceLevel() {
        return spiceLevel;
    }

    public void setSpiceLevel(SpiceLevel spiceLevel) {
        this.spiceLevel = spiceLevel;
    }

    public TasteLevel getTaste() {
        return taste;
    }

    public void setTaste(TasteLevel taste) {
        this.taste = taste;
    }

    public BigDecimal getBudgetMin() {
        return budgetMin;
    }

    public void setBudgetMin(BigDecimal budgetMin) {
        this.budgetMin = budgetMin;
    }

    public BigDecimal getBudgetMax() {
        return budgetMax;
    }

    public void setBudgetMax(BigDecimal budgetMax) {
        this.budgetMax = budgetMax;
    }
}

package com.webox.preference;

import org.springframework.data.jpa.repository.JpaRepository;

public interface PreferenceRepository extends JpaRepository<UserPreference, Long> {
}

package com.webox.preference.dto;

import com.webox.common.enums.Allergen;
import com.webox.common.enums.Category;
import com.webox.common.enums.SpiceLevel;
import com.webox.common.enums.TasteLevel;
import com.webox.preference.UserPreference;

import java.math.BigDecimal;
import java.util.List;

/** Preference payload — used for both GET (view) and PUT (update) of /api/preferences. */
public record PreferenceView(
        List<Allergen> allergens,
        List<Category> cuisines,
        SpiceLevel spiceLevel,
        TasteLevel taste,
        BigDecimal budgetMin,
        BigDecimal budgetMax) {

    public static PreferenceView empty() {
        return new PreferenceView(List.of(), List.of(), null, null, null, null);
    }

    public static PreferenceView of(UserPreference preference) {
        return new PreferenceView(
                preference.getAllergens(),
                preference.getCuisines(),
                preference.getSpiceLevel(),
                preference.getTaste(),
                preference.getBudgetMin(),
                preference.getBudgetMax());
    }
}

package com.webox.preference;

import com.webox.auth.UserRepository;
import com.webox.common.api.BizException;
import com.webox.common.api.ErrorCode;
import com.webox.preference.dto.PreferenceView;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.util.List;

@Service
public class PreferenceService {

    private final PreferenceRepository preferenceRepository;
    private final UserRepository userRepository;

    public PreferenceService(PreferenceRepository preferenceRepository, UserRepository userRepository) {
        this.preferenceRepository = preferenceRepository;
        this.userRepository = userRepository;
    }

    /** Employees without saved preferences get an empty view (never 404 — preferences are optional). */
    @Transactional(readOnly = true)
    public PreferenceView get(Long userId) {
        return preferenceRepository.findById(userId)
                .map(PreferenceView::of)
                .orElseGet(PreferenceView::empty);
    }

    @Transactional
    public PreferenceView put(Long userId, PreferenceView request) {
        validateBudget(request.budgetMin(), request.budgetMax());

        UserPreference preference = preferenceRepository.findById(userId).orElseGet(() -> {
            UserPreference created = new UserPreference();
            created.setUser(userRepository.getReferenceById(userId));
            return created;
        });
        preference.setAllergens(request.allergens() == null ? List.of() : request.allergens());
        preference.setCuisines(request.cuisines() == null ? List.of() : request.cuisines());
        preference.setSpiceLevel(request.spiceLevel());
        preference.setTaste(request.taste());
        preference.setBudgetMin(request.budgetMin());
        preference.setBudgetMax(request.budgetMax());
        return PreferenceView.of(preferenceRepository.save(preference));
    }

    private static void validateBudget(BigDecimal min, BigDecimal max) {
        if (min != null && min.signum() < 0 || max != null && max.signum() < 0) {
            throw new BizException(ErrorCode.VALIDATION_ERROR, "Budget cannot be negative.");
        }
        if (min != null && max != null && min.compareTo(max) > 0) {
            throw new BizException(ErrorCode.VALIDATION_ERROR,
                    "Budget minimum cannot exceed the maximum.");
        }
    }
}

package com.webox.preference;

import com.webox.auth.AuthContext;
import com.webox.preference.dto.PreferenceView;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/preferences")
public class PreferenceController {

    private final PreferenceService preferenceService;

    public PreferenceController(PreferenceService preferenceService) {
        this.preferenceService = preferenceService;
    }

    @GetMapping
    public PreferenceView get() {
        return preferenceService.get(AuthContext.require().id());
    }

    @PutMapping
    public PreferenceView put(@RequestBody PreferenceView request) {
        return preferenceService.put(AuthContext.require().id(), request);
    }
}
